export default function SuprimentosDashboard() {
  const rootRef = useRef(null);
  const initializedRef = useRef(false);
  const [chartReady, setChartReady] = useState(false);
  const [scriptError, setScriptError] = useState(null);

  const runDashboard = useCallback(() => {
    if (!chartReady || !rootRef.current || initializedRef.current) return;

    try {
      initializedRef.current = true;
      setScriptError(null);
      const execute = new Function(dashboardScript);
      execute();
    } catch (error) {
      initializedRef.current = false;
      console.error('Erro ao inicializar o painel de suprimentos:', error);
      setScriptError(error instanceof Error ? error.message : 'Erro desconhecido');
    }
  }, [chartReady]);

  useEffect(() => {
    runDashboard();
  }, [runDashboard]);

  return (
    <>
      <Script
        src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"
        strategy="afterInteractive"
        onLoad={() => setChartReady(true)}
        onError={() => setScriptError('Nao foi possivel carregar Chart.js.')}
      />
      <main ref={rootRef} dangerouslySetInnerHTML={{ __html: dashboardMarkup }} />
      {scriptError ? <div className="next-error">Erro ao carregar painel: {scriptError}</div> : null}
    </>
  );
}




